  ('bookkeeper-moex-02109', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依商業會計法規定，下列那一項敘述不屬於會計事項？', '["公司喪失一重要供應商客戶，預計將減少原料來源新臺幣1,000萬元", "營運使用之機器設備尚未完全折舊，帳面價值為新臺幣50萬元，報廢後閒置在倉庫", "向銀行申請變更契約，並增加銀行透支金額新臺幣80萬元", "公司宣告股東股利"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02110', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '忠勇公司業務人員王君出差搭乘計程車，車資計新臺幣 500 元，因行程匆促，並未向計程車司機索取計 程車資收據，王君如何向公司申請該筆車資？', '["不得申請，由王君自行負擔", "由王君告知公司會計人員製作傳票，憑以申請車資", "由王君及其主管填寫申請單共同證明出差事宜，憑以申請車資", "由王君報告公司負責人後，直接交代會計人員製作傳票，憑以申請車資"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02111', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '下列那一項不屬於商業會計法規定之原始憑證？', '["保險公司理賠給付通知書", "員工薪資扣繳憑單", "典當業之當票簿副聯", "銀行存款證明"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02112', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依商業會計法規定，若商業會計制度健全，使用總分類帳科目日計表者，得免設何種帳簿？', '["明細分類帳簿", "特種序時帳簿", "普通序時帳簿", "總分類帳簿"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02113', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '商業會計法關於會計憑證保管之規定，下列敘述何者錯誤？', '["各項會計憑證之保存，以會計年度決算經董事會承認後，至少保存五年", "記帳憑證於保管期限屆滿後，經代表商業之負責人核准，得予銷毀", "對外憑證，應至少自留副本或存根一份", "會計憑證，應按日或按月裝訂成冊"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02114', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '商業會計法關於有價證券投資之規定，下列敘述何者錯誤？', '["有價證券投資之入帳以取得時之實際成本為原則", "所有有價證券投資之期末評價方法，準用存貨成本計算方法", "具有控制能力之長期股權投資，採用權益法評價", "持有至到期日債券投資，應以攤銷後成本衡量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02115', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', 'A公司以一台機器設備交換B公司一台儀器設備，換入之儀器設備知悉製造之實際成本300,000元，惟無 公平價值可衡量，已知機器設備成本250,000元，累計折舊80,000元，A公司另支付現金60,000元給 B公司，請問A公司換入之儀器設備入帳金額為何？', '["230,000元", "170,000元", "300,000元", "360,000元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02116', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '商業會計法關於商業存貨會計處理之規定，下列敘述何者正確？', '["成本高於市價時，跌價損失應列為銷貨成本", "成本高於淨變現價值時，跌價損失應列為非營業損失", "後進先出法為存貨成本計算方法之一", "所謂淨變現價值，係指企業預期正常營業出售存貨所能取得之淨額"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02117', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '商業會計法關於固定資產提列折舊之規定，下列敘述何者正確？', '["固定資產之折舊方法，僅可採用一種方法，不得分類綜合計算之", "固定資產耐用年限已屆滿，仍可繼續使用時，得就殘值繼續提列折舊", "固定資產之折舊，得不必逐年提列", "定率遞減法不是商業會計法，而是所得稅法所規定的折舊方法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02118', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '商業會計法關於資產重估之規定，下列敘述何者正確？', '["經重估之固定資產應自重估年度起，按其重估後之價值計提折舊", "自用土地得按公告地價調整，而發生之增值不必減除估計土地增值稅準備，全數列為未實現重估增值", "租用他人資產得依法令規定，辦理資產重估", "無形資產重估後發生之增值，應列為業主權益項下之未實現重估增值"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
